export default async function ({ execution_id }) {
  const runCmd = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/wait-for-run-command-completed/result').then(r => r.json());
  const auto = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/wait-for-ssm-automation-completed/result').then(r => r.json());
  const status = (auto?.AutomationExecution?.AutomationExecutionStatus || auto?.AutomationExecutionStatus || '').toUpperCase();
  if (status !== 'SUCCESS') {
    throw new Error('Failover automation not successful: ' + status);
  }
  return { runCommand: runCmd, automation: auto, finalStatus: status };
}
